import{_ as a,o,c as n,j as e,a as r}from"./chunks/framework.DH-ORP1j.js";const _=JSON.parse('{"title":"秦始皇巩固统一的措施：①统一文字：小篆；","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-4.md","filePath":"notes/note-4.md"}'),s={name:"notes/note-4.md"};function c(d,t,l,i,p,m){return o(),n("div",null,[...t[0]||(t[0]=[e("h1",{id:"秦始皇巩固统一的措施-1统一文字-小篆",tabindex:"-1"},[r("秦始皇巩固统一的措施：①统一文字：小篆； "),e("a",{class:"header-anchor",href:"#秦始皇巩固统一的措施-1统一文字-小篆","aria-label":'Permalink to "秦始皇巩固统一的措施：①统一文字：小篆；"'},"​")],-1),e("p",null,"秦始皇巩固统一的措施：①统一文字：小篆；②统一度量衡；③统一车轨；④统一货币：圆形方孔半两钱；⑤统一岭南；⑥派蒙恬北击匈奴，修东起辽东，西至临洮的长城；⑦开凿灵渠。 秦朝疆域：东至东海，西到陇西，北至长城，南达南海。 汉武帝巩固大一统王朝的措施：①推恩令（主父偃），建立刺史制度；②罢黜百家，尊崇儒术（董仲舒），把儒家学说立为正统思想，兴办太学；③把铸币权收归中央，铸造五铢钱；实行盐铁官营专卖；④派张骞出使西域；⑤开辟陆上和海上丝绸之路；⑥派卫青、霍去病北击匈奴。 汉武帝从政治、经济、思想和军事等方面巩固了大一统的局面，使西汉开始进入鼎盛时期。 1、战国、秦国、李冰、都江堰、成都平原、岷江。 2、秦统一时间：前221年，定都：咸阳。 3、秦朝建立了君主专制中央集权制度。 4、影响：奠定了中国两千多年封建政治制度的基本格局，为历代王朝所沿用。封建社会后期阻碍社会进步。 5、大泽乡起义、陈胜吴广、前209年，张楚政权，我国历史上第一次农民起义。沉重打击秦朝的统治。 6、汉初，采取休养生息政策的皇帝有：汉高祖（刘邦）、文帝、景帝。 7、张骞第一次出使西域的目的：联络大月氏夹击匈奴；第二次：加强与西域各国的联系。 8、张骞出使西域的影响：开辟了通往西域的道路，促进汉朝与西域各国的相互了解与往来。促进东西方经济文化交流，为丝绸之路开通奠基。 9、东汉末年的农民起义是黄巾起义，张角。 10、华佗：东汉，麻沸散、外科手术、五禽戏 11、张仲景：东汉，《伤寒杂病论》，治未病。",-1)])])}const h=a(s,[["render",c]]);export{_ as __pageData,h as default};
